# scoring with an LLM propose-and-evaluate step at each agent; the DCOP
# backbone keeps global consistency without centralising private state.

# Why this works: no agent ever sees the whole problem; messages are bounded
# to constraint-neighbours; the algorithm terminates with each agent holding
# a value consistent with its neighbours and approximately globally optimal.
# Related: see `partial-global-planning`, `contract-net-protocol`.

subscribe(event_source) do |event|
    if not validate(event):
        reject(event); continue
    if seen_recently(event.id):       # idempotency / dedupe
        ack(event); continue
    if rate_limited():
        defer(event); continue

    try:
        result = agent.run(event.payload)
        record(event.id, result)
        ack(event)                     # ack only on success
    except Exception as exc:
        nack(event, reason=exc)        # let the source redeliver

