function spec_first_agent(spec_path):
    while not done(spec_path):
        spec = read(spec_path)              # single source of truth
        plan = agent.plan_from_spec(spec)

        for step in plan:
            run(step)                       # acts only against the spec

        # spec is the definition of done — the agent does NOT redefine it
        if agent.thinks_spec_changed_and_allowed():
            propose = agent.propose_spec_edit(spec)
            if reviewer.approve(propose):   # controlled update path
                write(spec_path, propose)

        if test_against_spec(spec_path):
            return "done"

function todo_driven_agent(goal, sandbox):
    # 1) author the plan as a file in the sandbox
    if not sandbox.exists("todo.md"):
        sandbox.write("todo.md", agent.draft_plan(goal))

    while true:
        todo = sandbox.read("todo.md")
        items = parse_checklist(todo)
        unticked = [i for i in items if not i.done]
        if not unticked:
            return agent.summarise(goal, todo)

        next_item = unticked[0]

        # re-inject the unticked tail into the prompt
        outcome = agent.run_one_turn(
            goal=goal,
            current_item=next_item,
            remaining=unticked,
        )

        # update the file: tick, add follow-ups, drop dead-ends
        todo = update_checklist(todo, next_item, outcome)
        sandbox.write("todo.md", todo)

